// ❌ BAD - public delegate field lets anyone invoke or clear subscribers
public class OrderService {
    public Action<int>? OrderShipped;
    public void Ship(int id) { OrderShipped(id); } // crash if null
}

// ✅ GOOD - event restricts external code; ?.Invoke is null-safe
public class OrderService {
    public event EventHandler<int>? OrderShipped;
    public void Ship(int id) {
        // process order...
        OrderShipped?.Invoke(this, id);
    }
}
var svc = new OrderService();
svc.OrderShipped += (_, id) => Console.WriteLine($"Order {id} shipped");
svc.Ship(42);

// ❌ BAD - object forces casting and loses type safety
public class Repository {
    public object GetById(int id) => _db.Find(id);
}
var p = (Product)repo.GetById(1); // cast can fail at runtime

// ✅ GOOD - generic with constraint; type-safe, no casting
public class Repository<T> where T : class, IEntity {
    private readonly AppDbContext _db;
    public Repository(AppDbContext db) => _db = db;
    public Task<T?> GetByIdAsync(int id) => _db.Set<T>().FindAsync(id).AsTask();
    public void Add(T entity) => _db.Set<T>().Add(entity);
}

// ❌ BAD - ToList() materialises the whole table, then filters in memory
var bad = db.Orders.ToList().Where(o => o.Status == OrderStatus.Shipped);

// ✅ GOOD - Where on IQueryable translates to SQL WHERE clause
var topCustomers = db.Orders
    .Where(o => o.Status == OrderStatus.Shipped)
    .GroupBy(o => o.CustomerId)
    .Select(g => new {
        CustomerId = g.Key,
        TotalSpend = g.Sum(o => o.Total),
        OrderCount = g.Count()
    })
    .OrderByDescending(x => x.TotalSpend)
    .Take(10)
    .ToList();

// ❌ BAD - long if/else chain with manual casting
string Describe(Shape shape) {
    if (shape is Circle) { var c = (Circle)shape; return $"Circle r={c.Radius}"; }
    else if (shape is Rectangle) { return "Rect"; }
    else return "Unknown";
}

// ✅ GOOD - switch expression: exhaustive, no casts, property patterns
string Describe(Shape shape) => shape switch {
    Circle { Radius: > 100 } c => $"Large circle r={c.Radius}",
    Circle c                   => $"Circle r={c.Radius}",
    Rectangle { Width: var w, Height: var h } when w == h => $"Square {w}x{h}",
    Rectangle r                => $"Rect {r.Width}x{r.Height}",
    null                       => "null",
    _                          => "Unknown shape"
};

// ❌ BAD - utility buried in a helper class, not discoverable via IntelliSense
public class StringHelper {
    public static string ToSlug(string s) => s.ToLower().Replace(' ', '-');
}
var slug = StringHelper.ToSlug(productName);

// ✅ GOOD - extension method surfaces in IntelliSense on the string itself
public static class StringExtensions {
    public static string ToSlug(this string s) =>
        s.ToLower().Replace(' ', '-');
}
var slug = productName.ToSlug(); // reads naturally
